@push('scripts')<script>
const typeField=document.getElementById('page_type');const related=document.querySelector('[data-related]');const pageKey=document.querySelector('[data-page-key]');const syncType=()=>{const type=typeField?.value;pageKey?.classList.toggle('d-none',type!=='static');const relatedTypes=['page','blog','blog_category','service','gallery'];related?.classList.toggle('d-none',!relatedTypes.includes(type));document.querySelectorAll('#related_id optgroup').forEach(group=>{group.disabled=group.dataset.type!==type;group.hidden=group.dataset.type!==type;});};typeField?.addEventListener('change',()=>{document.getElementById('related_id').value='';syncType();});syncType();document.querySelectorAll('input[type=file][data-preview]').forEach(input=>input.addEventListener('change',()=>{const file=input.files[0],preview=document.getElementById(input.dataset.preview);if(!file||!preview)return;preview.src=URL.createObjectURL(file);preview.classList.remove('d-none');document.getElementById(input.dataset.empty)?.classList.add('d-none');}));
</script>@endpush
